import { useState, useEffect, useRef } from "react";
import {
  LineChart, Line, AreaChart, Area, BarChart, Bar,
  RadialBarChart, RadialBar, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend
} from "recharts";

const COLORS = {
  bg: "#0a0d14",
  panel: "#0f1320",
  border: "#1e2535",
  accent: "#00d4ff",
  accent2: "#7c3aed",
  green: "#00e676",
  amber: "#ffab00",
  red: "#ff3d71",
  text: "#e2e8f0",
  muted: "#4a5568",
};

const GaugeChart = ({ value, label, color, icon }) => {
  const r = 52;
  const circ = 2 * Math.PI * r;
  const filled = (value / 100) * circ * 0.75;
  const gap = circ - filled;
  const rotation = -135;

  const getColor = (v) =>
    v > 85 ? COLORS.red : v > 65 ? COLORS.amber : color;

  const c = getColor(value);

  return (
    <div style={{
      background: COLORS.panel,
      border: `1px solid ${COLORS.border}`,
      borderRadius: 16,
      padding: "24px 20px",
      display: "flex",
      flexDirection: "column",
      alignItems: "center",
      gap: 8,
      position: "relative",
      overflow: "hidden",
    }}>
      <div style={{
        position: "absolute", top: 0, left: 0, right: 0,
        height: 2, background: `linear-gradient(90deg, transparent, ${c}, transparent)`
      }} />
      <svg width={130} height={100} viewBox="0 0 130 100">
        <circle cx={65} cy={72} r={r} fill="none" stroke="#1e2535" strokeWidth={10}
          strokeDasharray={`${circ * 0.75} ${circ * 0.25}`}
          strokeDashoffset={circ * 0.125}
          strokeLinecap="round"
          transform={`rotate(${rotation} 65 72)`}
        />
        <circle cx={65} cy={72} r={r} fill="none" stroke={c} strokeWidth={10}
          strokeDasharray={`${filled} ${gap + circ * 0.25}`}
          strokeDashoffset={circ * 0.125}
          strokeLinecap="round"
          transform={`rotate(${rotation} 65 72)`}
          style={{ transition: "stroke-dasharray 1s ease, stroke 0.5s ease" }}
        />
        <text x={65} y={68} textAnchor="middle" fill={c}
          style={{ fontSize: 22, fontWeight: 700, fontFamily: "monospace" }}>
          {value}%
        </text>
        <text x={65} y={84} textAnchor="middle" fill={COLORS.muted}
          style={{ fontSize: 11, fontFamily: "sans-serif" }}>
          {icon}
        </text>
      </svg>
      <span style={{ color: COLORS.muted, fontSize: 12, letterSpacing: 2, textTransform: "uppercase" }}>
        {label}
      </span>
    </div>
  );
};

const StatCard = ({ label, value, sub, accent }) => (
  <div style={{
    background: COLORS.panel,
    border: `1px solid ${COLORS.border}`,
    borderRadius: 12,
    padding: "16px 20px",
    position: "relative",
    overflow: "hidden",
  }}>
    <div style={{
      position: "absolute", left: 0, top: 0, bottom: 0,
      width: 3, background: accent, borderRadius: "2px 0 0 2px"
    }} />
    <div style={{ color: COLORS.muted, fontSize: 11, letterSpacing: 2, textTransform: "uppercase", marginBottom: 6 }}>
      {label}
    </div>
    <div style={{ color: COLORS.text, fontSize: 18, fontWeight: 600, fontFamily: "monospace" }}>
      {value}
    </div>
    {sub && <div style={{ color: COLORS.muted, fontSize: 12, marginTop: 4 }}>{sub}</div>}
  </div>
);

const CustomTooltip = ({ active, payload, label }) => {
  if (active && payload && payload.length) {
    return (
      <div style={{
        background: "#1a2035", border: `1px solid ${COLORS.border}`,
        borderRadius: 8, padding: "10px 14px", fontSize: 12,
      }}>
        {label && <div style={{ color: COLORS.muted, marginBottom: 6 }}>{label}</div>}
        {payload.map((p, i) => (
          <div key={i} style={{ color: p.color || COLORS.accent }}>
            {p.name}: <strong>{p.value}{p.unit || ""}</strong>
          </div>
        ))}
      </div>
    );
  }
  return null;
};

const formatBytes = (bytes) => {
  if (!bytes) return "0 B";
  const k = 1024;
  const sizes = ["B", "KB", "MB", "GB"];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return `${parseFloat((bytes / Math.pow(k, i)).toFixed(1))} ${sizes[i]}`;
};

export default function MetricsForm() {
  const [serverInfo, setServerInfo] = useState({ host: "", port: 22, username: "", password: "", name: "" });
  const [metrics, setMetrics] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [history, setHistory] = useState([]);
  const [activeTab, setActiveTab] = useState("overview");
  const historyRef = useRef([]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setServerInfo(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      const response = await fetch("http://localhost:8080/api/metrics/collect", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(serverInfo),
      });
      if (!response.ok) throw new Error("Connection failed — check host, port, username & password");
      const data = await response.json();
      setMetrics(data);

      const point = {
        time: new Date().toLocaleTimeString(),
        cpu: parseFloat(data.cpuUsage),
        memory: parseFloat(data.memoryUsage),
        disk: parseFloat(data.diskUsage),
      };
      historyRef.current = [...historyRef.current.slice(-19), point];
      setHistory([...historyRef.current]);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const inputStyle = {
    background: "#0a0d14",
    border: `1px solid ${COLORS.border}`,
    borderRadius: 8,
    color: COLORS.text,
    padding: "10px 14px",
    fontSize: 14,
    width: "100%",
    outline: "none",
    transition: "border-color 0.2s",
    fontFamily: "monospace",
    boxSizing: "border-box",
  };

  const tabs = ["overview", "performance", "processes", "network"];

  const processChartData = metrics?.topProcesses?.slice(0, 8).map(p => ({
    name: p.command?.split("/").pop()?.slice(0, 14) || p.command,
    cpu: parseFloat(p.cpu) || 0,
    memory: parseFloat(p.memory) || 0,
  })) || [];

  const diskPieData = metrics ? [
    { name: "Used", value: parseFloat(metrics.diskUsage) },
    { name: "Free", value: 100 - parseFloat(metrics.diskUsage) },
  ] : [];

  const memPieData = metrics ? [
    { name: "Used", value: parseFloat(metrics.memoryUsage) },
    { name: "Free", value: 100 - parseFloat(metrics.memoryUsage) },
  ] : [];

  return (
    <div style={{
      minHeight: "100vh",
      background: COLORS.bg,
      color: COLORS.text,
      fontFamily: "'Segoe UI', system-ui, sans-serif",
      padding: "0",
    }}>
      {/* Header */}
      <div style={{
        borderBottom: `1px solid ${COLORS.border}`,
        background: COLORS.panel,
        padding: "0 32px",
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        height: 60,
        position: "sticky", top: 0, zIndex: 100,
      }}>
        <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
          <div style={{
            width: 32, height: 32, borderRadius: 8,
            background: `linear-gradient(135deg, ${COLORS.accent}, ${COLORS.accent2})`,
            display: "flex", alignItems: "center", justifyContent: "center",
            fontSize: 16,
          }}>⚡</div>
          <div>
            <div style={{ fontWeight: 700, fontSize: 15, letterSpacing: 0.5 }}>ServerPulse</div>
            <div style={{ color: COLORS.muted, fontSize: 11, letterSpacing: 1 }}>METRICS DASHBOARD</div>
          </div>
        </div>
        {metrics && (
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <div style={{ width: 8, height: 8, borderRadius: "50%", background: COLORS.green, boxShadow: `0 0 8px ${COLORS.green}` }} />
            <span style={{ color: COLORS.green, fontSize: 12, fontFamily: "monospace" }}>
              {metrics.serverName} · {metrics.host}:{metrics.port}
            </span>
          </div>
        )}
      </div>

      <div style={{ maxWidth: 1200, margin: "0 auto", padding: "32px 24px" }}>

        {/* Connection Form */}
        <div style={{
          background: COLORS.panel,
          border: `1px solid ${COLORS.border}`,
          borderRadius: 16,
          padding: 28,
          marginBottom: 32,
        }}>
          <div style={{ marginBottom: 20, display: "flex", alignItems: "center", gap: 10 }}>
            <span style={{ color: COLORS.accent, fontSize: 16 }}>🔌</span>
            <span style={{ fontWeight: 600, letterSpacing: 0.5 }}>Server Connection</span>
          </div>

          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))", gap: 12 }}>
            {[
              { label: "Host / IP", name: "host", type: "text", placeholder: "192.168.1.1" },
              { label: "Port", name: "port", type: "number", placeholder: "22" },
              { label: "Username", name: "username", type: "text", placeholder: "root" },
              { label: "Password", name: "password", type: "password", placeholder: "••••••••" },
              { label: "Server Name", name: "name", type: "text", placeholder: "prod-server-01" },
            ].map(field => (
              <div key={field.name}>
                <label style={{ display: "block", color: COLORS.muted, fontSize: 11, letterSpacing: 1.5, textTransform: "uppercase", marginBottom: 6 }}>
                  {field.label}
                </label>
                <input
                  type={field.type}
                  name={field.name}
                  value={serverInfo[field.name]}
                  onChange={handleChange}
                  placeholder={field.placeholder}
                  style={inputStyle}
                  onFocus={e => e.target.style.borderColor = COLORS.accent}
                  onBlur={e => e.target.style.borderColor = COLORS.border}
                  required
                />
              </div>
            ))}
          </div>

          <button
            onClick={handleSubmit}
            disabled={loading}
            style={{
              marginTop: 20,
              padding: "11px 32px",
              background: loading ? COLORS.border : `linear-gradient(135deg, ${COLORS.accent}, ${COLORS.accent2})`,
              border: "none",
              borderRadius: 8,
              color: "#fff",
              fontWeight: 600,
              fontSize: 14,
              cursor: loading ? "not-allowed" : "pointer",
              letterSpacing: 0.5,
              display: "flex",
              alignItems: "center",
              gap: 8,
              transition: "opacity 0.2s",
            }}
          >
            {loading ? (
              <>
                <span style={{
                  width: 14, height: 14, border: `2px solid rgba(255,255,255,0.3)`,
                  borderTopColor: "#fff", borderRadius: "50%",
                  animation: "spin 0.8s linear infinite", display: "inline-block"
                }} />
                Connecting...
              </>
            ) : "▶ Fetch Metrics"}
          </button>

          {error && (
            <div style={{
              marginTop: 14, padding: "10px 16px",
              background: "rgba(255,61,113,0.1)", border: `1px solid rgba(255,61,113,0.3)`,
              borderRadius: 8, color: COLORS.red, fontSize: 13,
            }}>
              ⚠ {error}
            </div>
          )}
        </div>

        {metrics && (
          <>
            {/* Tabs */}
            <div style={{ display: "flex", gap: 4, marginBottom: 24, borderBottom: `1px solid ${COLORS.border}`, paddingBottom: 0 }}>
              {tabs.map(tab => (
                <button key={tab} onClick={() => setActiveTab(tab)} style={{
                  padding: "10px 20px",
                  background: "none",
                  border: "none",
                  borderBottom: activeTab === tab ? `2px solid ${COLORS.accent}` : "2px solid transparent",
                  color: activeTab === tab ? COLORS.accent : COLORS.muted,
                  cursor: "pointer",
                  fontSize: 13,
                  fontWeight: 600,
                  letterSpacing: 1,
                  textTransform: "uppercase",
                  transition: "all 0.2s",
                  marginBottom: -1,
                }}>
                  {tab}
                </button>
              ))}
            </div>

            {/* OVERVIEW TAB */}
            {activeTab === "overview" && (
              <>
                {/* Gauges */}
                <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))", gap: 16, marginBottom: 24 }}>
                  <GaugeChart value={parseFloat(metrics.cpuUsage) || 0} label="CPU Usage" color={COLORS.accent} icon="CPU" />
                  <GaugeChart value={parseFloat(metrics.memoryUsage) || 0} label="Memory" color={COLORS.accent2} icon="RAM" />
                  <GaugeChart value={parseFloat(metrics.diskUsage) || 0} label="Disk Usage" color={COLORS.green} icon="DISK" />
                </div>

                {/* Stat Cards */}
                <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))", gap: 12, marginBottom: 24 }}>
                  <StatCard label="Uptime" value={metrics.uptime} accent={COLORS.green} />
                  <StatCard label="Processes" value={metrics.processCount} accent={COLORS.accent} />
                  <StatCard label="Logged In Users" value={metrics.loggedInUsers} accent={COLORS.accent2} />
                  <StatCard label="Load Average" value={metrics.loadAverage?.join(" · ")} accent={COLORS.amber} />
                  <StatCard label="OS" value={metrics.osInfo} accent={COLORS.accent} />
                  <StatCard label="Swap" value={metrics.swapInfo} accent={COLORS.accent2} />
                </div>

                {/* Timestamp */}
                <div style={{ color: COLORS.muted, fontSize: 12, fontFamily: "monospace", textAlign: "right" }}>
                  Last updated: {metrics.timestamp}
                </div>
              </>
            )}

            {/* PERFORMANCE TAB */}
            {activeTab === "performance" && (
              <>
                {history.length > 1 && (
                  <div style={{
                    background: COLORS.panel, border: `1px solid ${COLORS.border}`,
                    borderRadius: 16, padding: 24, marginBottom: 20,
                  }}>
                    <div style={{ fontWeight: 600, marginBottom: 16, color: COLORS.text, fontSize: 14 }}>
                      📈 Historical Trend (last {history.length} polls)
                    </div>
                    <ResponsiveContainer width="100%" height={220}>
                      <AreaChart data={history}>
                        <defs>
                          <linearGradient id="cpu" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor={COLORS.accent} stopOpacity={0.3} />
                            <stop offset="95%" stopColor={COLORS.accent} stopOpacity={0} />
                          </linearGradient>
                          <linearGradient id="mem" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor={COLORS.accent2} stopOpacity={0.3} />
                            <stop offset="95%" stopColor={COLORS.accent2} stopOpacity={0} />
                          </linearGradient>
                        </defs>
                        <CartesianGrid strokeDasharray="3 3" stroke={COLORS.border} />
                        <XAxis dataKey="time" stroke={COLORS.muted} tick={{ fontSize: 11 }} />
                        <YAxis stroke={COLORS.muted} tick={{ fontSize: 11 }} domain={[0, 100]} unit="%" />
                        <Tooltip content={<CustomTooltip />} />
                        <Legend wrapperStyle={{ fontSize: 12, color: COLORS.muted }} />
                        <Area type="monotone" dataKey="cpu" stroke={COLORS.accent} fill="url(#cpu)" name="CPU" unit="%" />
                        <Area type="monotone" dataKey="memory" stroke={COLORS.accent2} fill="url(#mem)" name="Memory" unit="%" />
                        <Area type="monotone" dataKey="disk" stroke={COLORS.green} fill="none" strokeDasharray="4 4" name="Disk" unit="%" />
                      </AreaChart>
                    </ResponsiveContainer>
                  </div>
                )}

                <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20 }}>
                  {/* Memory Donut */}
                  <div style={{ background: COLORS.panel, border: `1px solid ${COLORS.border}`, borderRadius: 16, padding: 24 }}>
                    <div style={{ fontWeight: 600, marginBottom: 16, fontSize: 14 }}>🧠 Memory Breakdown</div>
                    <ResponsiveContainer width="100%" height={200}>
                      <PieChart>
                        <Pie data={memPieData} cx="50%" cy="50%" innerRadius={55} outerRadius={80}
                          dataKey="value" nameKey="name" paddingAngle={3}>
                          <Cell fill={COLORS.accent2} />
                          <Cell fill={COLORS.border} />
                        </Pie>
                        <Tooltip content={<CustomTooltip />} formatter={(v) => `${v.toFixed(1)}%`} />
                        <Legend wrapperStyle={{ fontSize: 12, color: COLORS.muted }} />
                      </PieChart>
                    </ResponsiveContainer>
                  </div>

                  {/* Disk Donut */}
                  <div style={{ background: COLORS.panel, border: `1px solid ${COLORS.border}`, borderRadius: 16, padding: 24 }}>
                    <div style={{ fontWeight: 600, marginBottom: 16, fontSize: 14 }}>💾 Disk Breakdown</div>
                    <ResponsiveContainer width="100%" height={200}>
                      <PieChart>
                        <Pie data={diskPieData} cx="50%" cy="50%" innerRadius={55} outerRadius={80}
                          dataKey="value" nameKey="name" paddingAngle={3}>
                          <Cell fill={COLORS.green} />
                          <Cell fill={COLORS.border} />
                        </Pie>
                        <Tooltip content={<CustomTooltip />} formatter={(v) => `${v.toFixed(1)}%`} />
                        <Legend wrapperStyle={{ fontSize: 12, color: COLORS.muted }} />
                      </PieChart>
                    </ResponsiveContainer>
                  </div>
                </div>
              </>
            )}

            {/* PROCESSES TAB */}
            {activeTab === "processes" && (
              <>
                {processChartData.length > 0 && (
                  <div style={{ background: COLORS.panel, border: `1px solid ${COLORS.border}`, borderRadius: 16, padding: 24, marginBottom: 20 }}>
                    <div style={{ fontWeight: 600, marginBottom: 16, fontSize: 14 }}>🔥 Top Processes — CPU & Memory</div>
                    <ResponsiveContainer width="100%" height={240}>
                      <BarChart data={processChartData} layout="vertical" barCategoryGap="20%">
                        <CartesianGrid strokeDasharray="3 3" stroke={COLORS.border} horizontal={false} />
                        <XAxis type="number" stroke={COLORS.muted} tick={{ fontSize: 11 }} unit="%" />
                        <YAxis type="category" dataKey="name" width={120} stroke={COLORS.muted} tick={{ fontSize: 11, fill: COLORS.muted }} />
                        <Tooltip content={<CustomTooltip />} />
                        <Legend wrapperStyle={{ fontSize: 12, color: COLORS.muted }} />
                        <Bar dataKey="cpu" fill={COLORS.accent} name="CPU %" radius={[0, 4, 4, 0]} />
                        <Bar dataKey="memory" fill={COLORS.accent2} name="Mem %" radius={[0, 4, 4, 0]} />
                      </BarChart>
                    </ResponsiveContainer>
                  </div>
                )}

                {/* Process Table */}
                <div style={{ background: COLORS.panel, border: `1px solid ${COLORS.border}`, borderRadius: 16, overflow: "hidden" }}>
                  <div style={{ padding: "16px 24px", borderBottom: `1px solid ${COLORS.border}`, fontWeight: 600, fontSize: 14 }}>
                    📋 Process Table
                  </div>
                  <table style={{ width: "100%", borderCollapse: "collapse" }}>
                    <thead>
                      <tr style={{ background: "#0a0d14" }}>
                        {["PID", "Command", "CPU %", "Memory %"].map(h => (
                          <th key={h} style={{
                            padding: "10px 20px", textAlign: "left",
                            color: COLORS.muted, fontSize: 11, letterSpacing: 1.5,
                            textTransform: "uppercase", fontWeight: 600,
                          }}>{h}</th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>
                      {metrics.topProcesses.map((proc, idx) => (
                        <tr key={idx} style={{
                          borderTop: `1px solid ${COLORS.border}`,
                          transition: "background 0.15s",
                        }}
                          onMouseEnter={e => e.currentTarget.style.background = "#1a2035"}
                          onMouseLeave={e => e.currentTarget.style.background = "transparent"}
                        >
                          <td style={{ padding: "11px 20px", fontFamily: "monospace", color: COLORS.accent, fontSize: 13 }}>{proc.pid}</td>
                          <td style={{ padding: "11px 20px", fontSize: 13, maxWidth: 300, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{proc.command}</td>
                          <td style={{ padding: "11px 20px" }}>
                            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                              <div style={{ flex: 1, height: 4, background: COLORS.border, borderRadius: 2, maxWidth: 80 }}>
                                <div style={{ height: "100%", width: `${Math.min(parseFloat(proc.cpu) * 2, 100)}%`, background: COLORS.accent, borderRadius: 2 }} />
                              </div>
                              <span style={{ fontFamily: "monospace", fontSize: 13, minWidth: 40 }}>{proc.cpu}%</span>
                            </div>
                          </td>
                          <td style={{ padding: "11px 20px" }}>
                            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                              <div style={{ flex: 1, height: 4, background: COLORS.border, borderRadius: 2, maxWidth: 80 }}>
                                <div style={{ height: "100%", width: `${Math.min(parseFloat(proc.memory) * 5, 100)}%`, background: COLORS.accent2, borderRadius: 2 }} />
                              </div>
                              <span style={{ fontFamily: "monospace", fontSize: 13, minWidth: 40 }}>{proc.memory}%</span>
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </>
            )}

            {/* NETWORK TAB */}
            {activeTab === "network" && (
              <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))", gap: 20 }}>
                <div style={{ background: COLORS.panel, border: `1px solid ${COLORS.border}`, borderRadius: 16, padding: 28 }}>
                  <div style={{ fontWeight: 600, marginBottom: 20, fontSize: 14 }}>🌐 Network I/O</div>
                  <div style={{ display: "flex", flexDirection: "column", gap: 20 }}>
                    {[
                      { label: "Bytes Received (RX)", value: formatBytes(metrics.network?.bytesReceived), raw: metrics.network?.bytesReceived, color: COLORS.green },
                      { label: "Bytes Sent (TX)", value: formatBytes(metrics.network?.bytesSent), raw: metrics.network?.bytesSent, color: COLORS.accent },
                    ].map(item => (
                      <div key={item.label}>
                        <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8 }}>
                          <span style={{ color: COLORS.muted, fontSize: 12 }}>{item.label}</span>
                          <span style={{ color: item.color, fontFamily: "monospace", fontSize: 14, fontWeight: 600 }}>{item.value}</span>
                        </div>
                        <div style={{ height: 6, background: COLORS.border, borderRadius: 3 }}>
                          <div style={{
                            height: "100%", borderRadius: 3,
                            width: `${Math.min((item.raw / Math.max(metrics.network?.bytesReceived, metrics.network?.bytesSent)) * 100, 100)}%`,
                            background: item.color,
                          }} />
                        </div>
                      </div>
                    ))}
                  </div>
                </div>

                <div style={{ background: COLORS.panel, border: `1px solid ${COLORS.border}`, borderRadius: 16, padding: 28 }}>
                  <div style={{ fontWeight: 600, marginBottom: 20, fontSize: 14 }}>📊 Network Chart</div>
                  <ResponsiveContainer width="100%" height={180}>
                    <BarChart data={[
                      { name: "RX", value: metrics.network?.bytesReceived || 0 },
                      { name: "TX", value: metrics.network?.bytesSent || 0 },
                    ]}>
                      <CartesianGrid strokeDasharray="3 3" stroke={COLORS.border} />
                      <XAxis dataKey="name" stroke={COLORS.muted} tick={{ fontSize: 12 }} />
                      <YAxis stroke={COLORS.muted} tick={{ fontSize: 11 }} tickFormatter={v => formatBytes(v)} />
                      <Tooltip content={<CustomTooltip />} formatter={v => formatBytes(v)} />
                      <Bar dataKey="value" radius={[6, 6, 0, 0]}>
                        <Cell fill={COLORS.green} />
                        <Cell fill={COLORS.accent} />
                      </Bar>
                    </BarChart>
                  </ResponsiveContainer>
                </div>

                <div style={{ background: COLORS.panel, border: `1px solid ${COLORS.border}`, borderRadius: 16, padding: 28 }}>
                  <div style={{ fontWeight: 600, marginBottom: 20, fontSize: 14 }}>ℹ️ System Details</div>
                  <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
                    {[
                      { k: "OS", v: metrics.osInfo },
                      { k: "Uptime", v: metrics.uptime },
                      { k: "Swap", v: metrics.swapInfo },
                      { k: "Load Avg", v: metrics.loadAverage?.join(" / ") },
                      { k: "Timestamp", v: metrics.timestamp },
                    ].map(item => (
                      <div key={item.k} style={{ display: "flex", justifyContent: "space-between", paddingBottom: 10, borderBottom: `1px solid ${COLORS.border}` }}>
                        <span style={{ color: COLORS.muted, fontSize: 12 }}>{item.k}</span>
                        <span style={{ color: COLORS.text, fontSize: 12, fontFamily: "monospace", textAlign: "right", maxWidth: "60%" }}>{item.v}</span>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            )}
          </>
        )}
      </div>

      <style>{`
        @keyframes spin { to { transform: rotate(360deg); } }
        * { box-sizing: border-box; }
        ::-webkit-scrollbar { width: 6px; }
        ::-webkit-scrollbar-track { background: #0a0d14; }
        ::-webkit-scrollbar-thumb { background: #1e2535; border-radius: 3px; }
        body { margin: 0; background: #0a0d14; }
      `}</style>
    </div>
  );
}
